{"code":"import json, re
# load uc pubnums from previous execute_python result
uc = var_call_J8cwNBnpSRpXJi7dXUOVqj77
uc_pubnums = set(uc.get('uc_pubnums', []))

# load all records with citations from file path
path = var_call_Faz9RVn2nfNdQTGdpE3LNGkN
with open(path, 'r', encoding='utf-8') as f:
    data = json.load(f)

assignee_map = {}  # assignee -> set of primary cpc codes

for rec in data:
    patinfo = rec.get('Patents_info','')
    citation_str = rec.get('citation','')
    if not citation_str or citation_str.strip() == '[]':
        continue
    # parse citation JSON if possible
    try:
        cites = json.loads(citation_str)
    except Exception:
        # try to fix single quotes
        try:
            cites = json.loads(citation_str.replace("'", '"'))
        except Exception:
            cites = []
    cites_pubnums = set()
    for c in cites:
        pn = c.get('publication_number','')
        if pn:
            cites_pubnums.add(pn)
    # check intersection
    if uc_pubnums.intersection(cites_pubnums):
        # extract assignee from Patents_info
        # patterns: 'HOLD(S) the', 'is assigned to', 'is owned by', 'holds the', etc
        m = re.search(r'^(.*?)\s+(?:holds|holds the|is assigned to|is owned by|owns|owned by|assigned to|has)\b', patinfo, re.IGNORECASE)
        if m:
            assignee = m.group(1).strip()
        else:
            # fallback: take leading uppercase words until a lowercase verb
            m2 = re.match(r'^([A-Z0-9 &,\.\-]+)', patinfo)
            assignee = m2.group(1).strip() if m2 else patinfo.strip()
        # ignore UNIV CALIFORNIA exact
        if assignee.upper() == 'UNIV CALIFORNIA':
            continue
        # parse cpc field
        cpc_str = rec.get('cpc','')
        primary_code = None
        try:
            cpcs = json.loads(cpc_str) if cpc_str else []
        except Exception:
            try:
                cpcs = json.loads(cpc_str.replace("'", '"'))
            except Exception:
                cpcs = []
        # find first where first==True
        for entry in cpcs:
            if isinstance(entry, dict) and entry.get('first') is True:
                primary_code = entry.get('code')
                break
        if not primary_code and cpcs:
            # take first code
            for entry in cpcs:
                if isinstance(entry, dict) and entry.get('code'):
                    primary_code = entry.get('code')
                    break
        if not primary_code:
            primary_code = None
        assignee_map.setdefault(assignee, set())
        if primary_code:
            assignee_map[assignee].add(primary_code)

# convert sets to lists
assignee_map_list = {k: sorted(list(v)) for k,v in assignee_map.items()}
all_codes = sorted(list({code for codes in assignee_map_list.values() for code in codes}))

result = {'assignee_to_codes': assignee_map_list, 'codes': all_codes}
print('__RESULT__:')
print(json.dumps(result))"}

